const now = new Date();
const todayISO = now.toISOString();

const d7 = new Date(now);
d7.setDate(d7.getDate() - 7);

const d30 = new Date(now);
d30.setDate(d30.getDate() - 30);

return [{
  json: {
    todayISO,
    today: now.toISOString().substring(0, 10),
    d7ISO: d7.toISOString(),
    d30ISO: d30.toISOString()
  }
}];

const activeTicketsRaw = $('Get Active Tickets').all().map(i => i.json);
const closed7d = $('Get Closed Last 7 Days').all().map(i => i.json);
const created7d = $('Get Created Last 7 Days').all().map(i => i.json);
const updated7d = $('Get Updated Last 7 Days').all().map(i => i.json);
const slaTickets30d = $('Get Tickets for SLA 30d').all().map(i => i.json);
const pastDue = $('Get Past Due Schedules').all().map(i => i.json);
const dates = $('Set Date Ranges').first().json;

let gotoCalls = [];
try {
  const gotoData = $('Get GoTo Calls 7d').first().json;
  gotoCalls = gotoData.items || [];
} catch(e) {}

// --- ACTIVE TICKET FILTERS ---
// Exclude "parked" statuses (Waiting, Scheduled, Recurring, etc.)
// BG only counts tickets actively being worked or needing attention
const parkedStatuses = [
  'scheduled', 'recurring', 'monthly', 'next onsite',
  'waiting on client', 'waiting on 3rd party', 'on-hold',
  'sign off', 'pending close', 'pending close*',
  'ncr closed', 'completed', 'completed*', 'closed',
  'closed*', 'closed-duplicate', 'closed-norespo',
  'completed-duplicate', 'completed-noresponse',
  'completed-survey*', 'completed-delete', 'completed-test*',
  'enter time', 'accounting', 'accounting*'
];
const excludedBoards = ['automated alerts'];

const activeTickets = activeTicketsRaw.filter(t => {
  // Exclude parked/waiting statuses
  const statusName = (t.status && t.status.name) ? t.status.name.toLowerCase() : '';
  if (parkedStatuses.some(s => statusName === s || statusName.startsWith(s))) return false;
  // Exclude Automated Alerts board
  const boardName = (t.board && t.board.name) ? t.board.name.toLowerCase() : '';
  if (excludedBoards.some(b => boardName.includes(b))) return false;
  return true;
});

// --- ACTIVE METRICS ---
const activeTotal = activeTickets.length;

// Managed Services: tickets on boards related to managed services
// BG's "Managed Services" likely = Professional Services board with managed service agreements
// For now: filter to Professional Services board (PSG)
const activeManagedServices = activeTickets.filter(t =>
  t.board && t.board.name && t.board.name.toLowerCase().includes('professional')
).length;

// Block Time: may be a specific agreement type or board
const activeBlockTime = activeTickets.filter(t =>
  t.board && t.board.name && t.board.name.toLowerCase().includes('block')
).length;

const activeUnassigned = activeTickets.filter(t =>
  !t.owner || !t.owner.id || t.owner.identifier === 'zvirtual'
).length;

// --- CLOSED/CREATED METRICS (include ALL, like BG does) ---
const pastDueCount = pastDue.length;
const closedCount7d = closed7d.length;

let avgHrsComplete = 0;
const closedWithHours = closed7d.filter(t => (t.actualHours || 0) > 0);
if (closedWithHours.length > 0) {
  avgHrsComplete = closedWithHours.reduce((sum, t) => sum + (t.actualHours || 0), 0) / closedWithHours.length;
}

const createdCount7d = created7d.length;
const netTickets7d = createdCount7d - closedCount7d;
const totalUpdated7d = updated7d.length;
const netUpdates7d = totalUpdated7d - createdCount7d;
const killRate7d = createdCount7d > 0 ? (closedCount7d / createdCount7d * 100) : 100;

// --- SLA (exclude auto-resolved and waiting) ---
function isAutoResolved(t) {
  return t.closedFlag === true && (t.respondMinutes || 0) === 0 && (t.resolveMinutes || 0) === 0;
}

const d7 = new Date(dates.d7ISO);
const slaFiltered30d = slaTickets30d.filter(t => !isAutoResolved(t) && t.slaStatus !== 'Waiting');
const slaFiltered7d = slaFiltered30d.filter(t => {
  try { return new Date(t.dateEntered) >= d7; } catch(e) { return false; }
});

function isBreached(t) {
  if (t.closedFlag) return false;
  return t.isInSla === false;
}

const b7 = slaFiltered7d.filter(t => isBreached(t)).length;
const slaMet7d = slaFiltered7d.length > 0 ? ((slaFiltered7d.length - b7) / slaFiltered7d.length * 100) : 100;
const b30 = slaFiltered30d.filter(t => isBreached(t)).length;
const slaMet30d = slaFiltered30d.length > 0 ? ((slaFiltered30d.length - b30) / slaFiltered30d.length * 100) : 100;

// --- CALLS ---
const inboundCalls = gotoCalls.filter(c => c.direction === 'INBOUND').length;
const outboundCalls = gotoCalls.filter(c => c.direction === 'OUTBOUND').length;
let avgCallLengthMin = 0;
const answeredCalls = gotoCalls.filter(c => c.callAnswered && c.callEnded);
if (answeredCalls.length > 0) {
  const totalMinutes = answeredCalls.reduce((sum, c) => {
    return sum + (new Date(c.callEnded) - new Date(c.callAnswered)) / 60000;
  }, 0);
  avgCallLengthMin = totalMinutes / answeredCalls.length;
}

const today = dates.today;
return [
  { metric_name: 'active_total', metric_value: activeTotal, category: 'tickets' },
  { metric_name: 'active_managed_services', metric_value: activeManagedServices, category: 'tickets' },
  { metric_name: 'active_block_time', metric_value: activeBlockTime, category: 'tickets' },
  { metric_name: 'active_unassigned', metric_value: activeUnassigned, category: 'tickets' },
  { metric_name: 'checklist_count', metric_value: 0, category: 'tickets' },
  { metric_name: 'checklist_unassigned', metric_value: 0, category: 'tickets' },
  { metric_name: 'no_future_schedule', metric_value: 0, category: 'tickets' },
  { metric_name: 'past_due_schedules', metric_value: pastDueCount, category: 'tickets' },
  { metric_name: 'closed_7d', metric_value: closedCount7d, category: 'tickets' },
  { metric_name: 'avg_hrs_complete_7d', metric_value: Math.round(avgHrsComplete * 100) / 100, category: 'tickets' },
  { metric_name: 'net_tickets_7d', metric_value: netTickets7d, category: 'tickets' },
  { metric_name: 'net_updates_7d', metric_value: netUpdates7d, category: 'tickets' },
  { metric_name: 'total_updated_7d', metric_value: totalUpdated7d, category: 'tickets' },
  { metric_name: 'kill_rate_7d', metric_value: Math.round(killRate7d * 100) / 100, category: 'tickets' },
  { metric_name: 'sla_met_7d', metric_value: Math.round(slaMet7d * 100) / 100, category: 'sla' },
  { metric_name: 'sla_met_30d', metric_value: Math.round(slaMet30d * 100) / 100, category: 'sla' },
  { metric_name: 'calls_inbound', metric_value: inboundCalls, category: 'calls' },
  { metric_name: 'calls_outbound', metric_value: outboundCalls, category: 'calls' },
  { metric_name: 'calls_avg_length_min', metric_value: Math.round(avgCallLengthMin * 100) / 100, category: 'calls' }
].map(m => ({ json: { ...m, snapshot_date: today } }));

